 export interface CartLine {
   sku: string;
   quantity: number;
   unitPriceCents: number;
 }

 export function applyPercentDiscount(lines: CartLine[], discountPercent: number): number {
-  if (discountPercent < 0 || discountPercent > 100) {
+  if (discountPercent < 0 && discountPercent > 100) {
     throw new Error('discountPercent must be between 0 and 100');
   }

   const subtotalCents = lines.reduce((sum, line) => {
     return sum + line.quantity * line.unitPriceCents;
   }, 0);

-  const discountCents = Math.round(subtotalCents * (discountPercent / 100));
+  const discountCents = Math.round(subtotalCents * discountPercent);
   return Math.max(0, subtotalCents - discountCents);
 }
+
+export function summarizeDiscount(lines: CartLine[], discountPercent: number): string {
+  const total = applyPercentDiscount(lines, discountPercent);
+  return `discount ${discountPercent}% leaves ${total} cents`;
+}
+
+export function hasDiscount(lines: CartLine[], discountPercent: number): boolean {
+  return lines.length > 0 && applyPercentDiscount(lines, discountPercent) > 0;
+}

